        if (!is_null($BookingStatus) && !in_array($BookingStatus, $allowedValues, true)) {
            throw new \InvalidArgumentException(
                sprintf(
                    "Invalid value for 'BookingStatus', must be one of '%s'",
                    implode("', '", $allowedValues)
                )
            );
        }
        $this->container['BookingStatus'] = $BookingStatus;

        return $this;
    }

    /**
     * Gets VirtualStreamLink
     *
     * @return string
     */
    public function getVirtualStreamLink(): string
    {
        return $this->container['VirtualStreamLink'];
    }

    /**
     * Sets VirtualStreamLink
     *
     * @param string $VirtualStreamLink The URL for the live stream for the class if hosted on the mindbody virtual wellness platform
     *
     * @return $this
     */
    public function setVirtualStreamLink($VirtualStreamLink): self
    {
        $this->container['VirtualStreamLink'] = $VirtualStreamLink;

        return $this;
    }
    
}


